const comments={_attachments:[],getAntiForgeryToken:function(){const a=document.querySelector('input[name="__RequestVerificationToken"]');return a?a.value:''},getHeaders:function(){return{'RequestVerificationToken':this.getAntiForgeryToken(),'Content-Type':'application/json'}},toggleForm:function(a){const b=document.getElementById('comment-form');const c=document.getElementById('comment-replied-on');if(b.style.display==='none'){b.style.display='block';if(a){c.value=a}else{c.value=''}document.getElementById('comment-text').focus()}else{b.style.display='none';c.value='';document.getElementById('comment-text').value='';this._attachments=[];this.renderAttachmentList()}},initAttachmentUpload:function(){const a=this;const b=document.getElementById('comment-attachment');if(b){b.addEventListener('change',async function(c){const d=c.target.files;if(!d.length)return;for(let e=0;e<d.length;e++){await a.uploadFile(d[e])}b.value=''})}},uploadFile:async function(a){const b=new FormData();b.append('files',a);try{const c=await fetch('/Admin/Media/Upload?path=comments&extensions=.jpg,.jpeg,.png,.gif,.pdf,.doc,.docx,.xls,.xlsx',{method:'POST',headers:{'RequestVerificationToken':this.getAntiForgeryToken()},body:b});if(c.ok){const d=await c.json();if(d.files&&d.files.length>0){for(const e of d.files){this._attachments.push({name:e.name,path:e.path||e.url,size:e.size,type:e.type||a.type})}this.renderAttachmentList()}}else{alert('Failed to upload file: '+a.name)}}catch(f){alert('Upload error: '+f.message)}},removeAttachment:function(a){this._attachments.splice(a,1);this.renderAttachmentList()},renderAttachmentList:function(){const a=document.getElementById('comment-attachment-list');if(!a)return;a.innerHTML='';for(let b=0;b<this._attachments.length;b++){const c=this._attachments[b];const d=document.createElement('span');d.className='badge bg-light text-dark d-inline-flex align-items-center gap-1';d.innerHTML='<i class="fas fa-paperclip"></i> '+this.escapeHtml(c.name)+' <button type="button" class="btn-close btn-close-sm ms-1" onclick="comments.removeAttachment('+b+')" aria-label="Remove"></button>';a.appendChild(d)}},escapeHtml:function(a){const b=document.createElement('div');b.textContent=a;return b.innerHTML},submit:async function(){const a=document.querySelector('.comments-section');const b=a.dataset.commentedOn;const c=document.getElementById('comment-text').value.trim();const d=document.getElementById('comment-replied-on').value;if(!c){alert('Please enter a comment.');return}const e=this._attachments.map(function(f){return f.path});try{const f=await fetch('/api/comments/create',{method:'POST',headers:this.getHeaders(),body:JSON.stringify({commentedOn:b,repliedOn:d||null,text:c,attachments:e})});if(f.ok){const g=await f.json();if(g.success){window.location.reload()}}else if(f.status===403){alert('You are not authorized to comment.')}else{alert('Failed to submit comment.')}}catch(h){alert('Network error: '+h.message)}},reply:function(a){this.toggleForm(a)},deleteComment:async function(a){if(!confirm('Are you sure you want to delete this comment?'))return;try{const b=await fetch('/api/comments/'+a+'/delete',{method:'POST',headers:this.getHeaders()});if(b.ok){window.location.reload()}}catch(c){alert('Network error: '+c.message)}},updateStatus:async function(a,b){try{const c=await fetch('/api/comments/'+a+'/status',{method:'POST',headers:this.getHeaders(),body:JSON.stringify({status:b})});if(c.ok){window.location.reload()}}catch(d){alert('Network error: '+d.message)}},edit:async function(a){const b=prompt('Edit your comment:');if(!b)return;try{const c=await fetch('/api/comments/'+a+'/update',{method:'POST',headers:this.getHeaders(),body:JSON.stringify({text:b})});if(c.ok){window.location.reload()}}catch(d){alert('Network error: '+d.message)}}};document.addEventListener('DOMContentLoaded',function(){comments.initAttachmentUpload()});
